import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { EventBus } from '../../src/events/event-bus.js';
import { OrderService, resetOrderIdCounter } from '../../src/services/order.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { User } from '../../src/models/user.js';

describe('Event-based notification flow', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let eventBus: EventBus;
  let orderService: OrderService;
  let notificationService: NotificationService;
  let testUser: User;

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    eventBus = new EventBus();
    orderService = new OrderService(orderRepo, userRepo, eventBus);
    notificationService = new NotificationService(eventBus);
    resetOrderIdCounter();
    resetNotificationIdCounter();

    testUser = {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    };
    userRepo.save(testUser);
  });

  it('should notify on order creation via EventBus', async () => {
    await orderService.createOrder({
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
    });

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]?.recipient).toBe('alice@example.com');
    expect(notifications[0]?.subject).toContain('Order Confirmation');
    expect(notifications[0]?.body).toContain('Widget x2');
    expect(notifications[0]?.body).toContain('$20.00');
  });

  it('should notify on status change via EventBus', async () => {
    const order = await orderService.createOrder({
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
    });

    await orderService.updateOrderStatus(order.id, 'confirmed');

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(2);
    expect(notifications[1]?.subject).toContain('Order Update');
    expect(notifications[1]?.body).toContain('pending');
    expect(notifications[1]?.body).toContain('confirmed');
  });

  it('should emit all events through EventBus for full order lifecycle', async () => {
    const order = await orderService.createOrder({
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 15 }],
    });

    await orderService.updateOrderStatus(order.id, 'confirmed');
    await orderService.updateOrderStatus(order.id, 'shipped');
    await orderService.updateOrderStatus(order.id, 'delivered');

    const events = eventBus.getEventLog();
    expect(events).toHaveLength(4);
    expect(events[0]?.type).toBe('order:created');
    expect(events[1]?.type).toBe('order:status-changed');
    expect(events[2]?.type).toBe('order:status-changed');
    expect(events[3]?.type).toBe('order:status-changed');

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(4);
    expect(notifications[0]?.subject).toContain('Order Confirmation');
    expect(notifications[1]?.body).toContain('pending to confirmed');
    expect(notifications[2]?.body).toContain('confirmed to shipped');
    expect(notifications[3]?.body).toContain('shipped to delivered');
  });

  it('should not send notifications when no listener is registered', async () => {
    const isolatedEventBus = new EventBus();
    const isolatedOrderService = new OrderService(orderRepo, userRepo, isolatedEventBus);

    await isolatedOrderService.createOrder({
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
    });

    // Events are emitted but no NotificationService is listening
    const events = isolatedEventBus.getEventLog();
    expect(events).toHaveLength(1);
    expect(events[0]?.type).toBe('order:created');
  });

  it('should support multiple listeners on the same event', async () => {
    let secondListenerCalled = false;
    eventBus.on('order:created', () => {
      secondListenerCalled = true;
    });

    await orderService.createOrder({
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
    });

    expect(secondListenerCalled).toBe(true);
    expect(notificationService.getNotificationCount()).toBe(1);
  });
